#include <stdio.h>
#include <math.h>

void djelitelji(int x) {
    int i;
    printf("\nDjelitelji broja %d su: \n", x);
    int limit = (int) sqrt(x);
    for (i = 1; i <= limit; i++) {
        if (x % i == 0) {
            printf("%d ", i);
            if (i != x / i) {
                printf("%d ", x / i);
            }
        }
    }
}

int main() {
    int n;
    printf("Unesite prirodan broj: ");
    scanf("%d", &n);

    if (n <= 0) {
        printf("Broj mora biti prirodan.\n");
        return 1;
    }

    djelitelji(n);

    return 0;
}
